namespace FlawlessChips.Tests;

public class FlawlessTiaTests
{
    [Test]
    public async Task TestStartupStateMatchesSim2600()
    {
        var chip = new FlawlessTia();

        using var _ = chip.BeginLogging("TIA_FlawlessChips.txt");

        chip.Startup();

        // This state was retrieved from Sim2600 by running the equivalent simulation.
        await Assert.That(chip.GetState()).IsEqualTo(
            "");
    }

